SELECT COUNT(DISTINCT ppnt_id) AS patient_count
FROM drug_records
WHERE regi_code = '0';

SELECT SUM(drme_dru) AS total_drug_administered
FROM drug_records
WHERE ppnt_id = 0;

SELECT COUNT(drme_id) AS drug_administrations_count
FROM drug_records
WHERE ppnt_id = 1;

SELECT drme_outcome
FROM drug_records
WHERE ppnt_code = 'BAOL086X';

SELECT ppnt_id, MAX(drme_dru) AS max_drug_administered
FROM drug_records
GROUP BY ppnt_id;

SELECT COUNT(DISTINCT ppnt_id) AS patient_count
FROM drug_records
WHERE regi_code = '0';
